      IntArray::full(a, n, l)
    Ensure
      __return == second_largest_list(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int max1 = a[0];
    int max2 = a[1];

    if (max2 > max1) {
        int t = max1;
        max1 = max2;
        max2 = t;
    }

    /*@ Inv
          2 <= i && i <= n &&
          n == n@pre &&
          a == a@pre &&
          second_largest_acc(max1, max2, sublist(i, n, l)) == second_largest_list(l) &&
          IntArray::full(a, n, l)
    */
    for (i = 2; i < n; ++i) {
        if (a[i] > max1) {
            max2 = max1;
            max1 = a[i];
        } else if (a[i] > max2) {
            max2 = a[i];
        }
    }

    return max2;
}
